 1→import React from 'react';
 2→import {NavigationContainer} from '@react-navigation/native';
 3→import {createNativeStackNavigator} from '@react-navigation/native-stack';
 4→import HomeScreen from './src/screens/HomeScreen';
 5→import ResultScreen from './src/screens/ResultScreen';
 6→import SettingsScreen from './src/screens/SettingsScreen';
 7→
 8→const Stack = createNativeStackNavigator();
 9→
10→export default function App() {
11→  return (
12→    <NavigationContainer>
13→      <Stack.Navigator
14→        screenOptions={{
15→          headerStyle: {backgroundColor: '#1a73e8'},
16→          headerTintColor: '#fff',
17→        }}>
18→        <Stack.Screen name="Home" component={HomeScreen} options={{title: '录音文档对比'}} />
19→        <Stack.Screen name="Result" component={ResultScreen} options={{title: '对比结果'}} />
20→        <Stack.Screen name="Settings" component={SettingsScreen} options={{title: '设置'}} />
21→      </Stack.Navigator>
22→    </NavigationContainer>
23→  );
24→}
