 1→import AsyncStorage from '@react-native-async-storage/async-storage';
 2→
 3→// 转写服务商
 4→export const ASR_PROVIDERS = {
 5→  aliyun: {name: '阿里云语音识别', region: 'cn'},
 6→  xfyun: {name: '讯飞语音识别', region: 'cn'},
