 8→  baidu: {name: '百度语音识别', region: 'cn'},
 9→  openai_whisper: {name: 'OpenAI Whisper', region: 'intl'},
10→  google: {name: 'Google Speech', region: 'intl'},
11→  azure: {name: 'Azure语音识别', region: 'intl'},
12→  aws: {name: 'AWS Transcribe', region: 'intl'},
