14→
15→// 大模型服务商
16→export const LLM_PROVIDERS = {
17→  // 国内
18→  zhipu: {name: '智谱GLM', region: 'cn', endpoint: 'https://open.bigmodel.cn/api/paas/v4/chat/completions', defaultModel: 'glm-4-flash'},
