20→  qwen: {name: '通义千问', region: 'cn', endpoint: 'https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', defaultModel: 'qwen-turbo'},
21→  doubao: {name: '豆包(字节)', region: 'cn', endpoint: 'https://ark.cn-beijing.volces.com/api/v3/chat/completions', defaultModel: 'doubao-pro-4k'},
22→  // 国际
23→  openai: {name: 'OpenAI', region: 'intl', endpoint: 'https://api.openai.com/v1/chat/completions', defaultModel: 'gpt-4o-mini'},
24→  claude: {name: 'Claude', region: 'intl', endpoint: 'https://api.anthropic.com/v1/messages', defaultModel: 'claude-sonnet-4-20250514'},
25→  gemini: {name: 'Gemini', region: 'intl', endpoint: 'https://generativelanguage.googleapis.com/v1beta/chat/completions', defaultModel: 'gemini-2.0-flash'},
