29→export type AsrProviderId = keyof typeof ASR_PROVIDERS;
30→export type LlmProviderId = keyof typeof LLM_PROVIDERS;
31→
32→export interface AppConfig {
33→  // 当前选择的服务商
34→  asrProvider: AsrProviderId;
35→  llmProvider: LlmProviderId;
36→  // 各服务商的API Key（key为provider id）
37→  asrKeys: Record<string, {key: string; secret?: string; appKey?: string; region?: string}>;
38→  llmKeys: Record<string, {key: string; model?: string}>;
39→}
40→
41→const CONFIG_KEY = 'app_config_v2';
42→
43→const DEFAULT_CONFIG: AppConfig = {
44→  asrProvider: 'aliyun',
45→  llmProvider: 'zhipu',
46→  asrKeys: {},
47→  llmKeys: {},
48→};
49→
50→export async function getConfig(): Promise<AppConfig> {
51→  const raw = await AsyncStorage.getItem(CONFIG_KEY);
52→  if (!raw) return DEFAULT_CONFIG;
53→  try {
54→    return {...DEFAULT_CONFIG, ...JSON.parse(raw)};
55→  } catch {
56→    return DEFAULT_CONFIG;
57→  }
58→}
59→
60→export async function saveConfig(config: AppConfig) {
61→  await AsyncStorage.setItem(CONFIG_KEY, JSON.stringify(config));
62→}
63→
64→export function isConfigValid(config: AppConfig): boolean {
65→  const asrKey = config.asrKeys[config.asrProvider];
66→  const llmKey = config.llmKeys[config.llmProvider];
67→  return !!(asrKey?.key && llmKey?.key);
68→}
