  1→import {LLM_PROVIDERS, LlmProviderId, AppConfig} from '../utils/config';
  2→
  3→export interface DiffItem {
  4→  docText: string;
  5→  audioText: string;
  6→  type: 'mismatch' | 'missing_in_audio' | 'extra_in_audio';
  7→  position: number;
  8→}
  9→
 10→export interface CompareResult {
 11→  diffs: DiffItem[];
 12→  summary: string;
 13→}
 14→
 15→const PROMPT_TEMPLATE = (audioText: string, docText: string) => `你是一个专业的文档校对助手。请对比以下两段文字，找出所有不一致的地方。
 16→
 17→【录音转写文字】
 18→${audioText}
 19→
 20→【Word文档原文】
 21→${docText}
 22→
 23→请以JSON格式返回对比结果，格式如下：
 24→{
 25→  "diffs": [
 26→    {
 27→      "docText": "文档中的原文片段",
 28→      "audioText": "录音中对应的文字（如果有）",
 29→      "type": "mismatch 或 missing_in_audio 或 extra_in_audio",
 30→      "position": 段落索引号（从0开始）
 31→    }
 32→  ],
 33→  "summary": "总结说明，共发现多少处不一致"
 34→}
 35→
 36→注意：
 37→- mismatch: 两边都有但内容不同
 38→- missing_in_audio: 文档有但录音没提到
 39→- extra_in_audio: 录音有但文档没有
 40→- 语义相同但表述不同的不算差异（如"价格高"和"价格偏高"算一致）
 41→- 口语化表达和书面表达的差异不算差异
 42→- 只返回JSON，不要其他内容`;
 43→
 44→async function callClaudeApi(prompt: string, apiKey: string, model: string): Promise<string> {
 45→  const resp = await fetch('https://api.anthropic.com/v1/messages', {
 46→    method: 'POST',
 47→    headers: {
 48→      'Content-Type': 'application/json',
 49→      'x-api-key': apiKey,
 50→      'anthropic-version': '2023-06-01',
 51→    },
 52→    body: JSON.stringify({
 53→      model,
 54→      max_tokens: 4096,
 55→      messages: [{role: 'user', content: prompt}],
 56→    }),
 57→  });
 58→  const data = await resp.json();
 59→  return data?.content?.[0]?.text || '';
 60→}
 61→
 62→async function callOpenAICompatible(prompt: string, apiKey: string, endpoint: string, model: string): Promise<string> {
 63→  const resp = await fetch(endpoint, {
 64→    method: 'POST',
 65→    headers: {
 66→      'Content-Type': 'application/json',
 67→      Authorization: `Bearer ${apiKey}`,
 68→    },
 69→    body: JSON.stringify({
 70→      model,
 71→      messages: [{role: 'user', content: prompt}],
 72→      temperature: 0.1,
 73→    }),
 74→  });
 75→  const data = await resp.json();
 76→  return data?.choices?.[0]?.message?.content || '';
 77→}
 78→
 79→export async function compareTexts(
 80→  audioText: string,
 81→  docText: string,
 82→  config: AppConfig,
 83→): Promise<CompareResult> {
 84→  const providerId = config.llmProvider;
 85→  const provider = LLM_PROVIDERS[providerId];
 86→  const keyConfig = config.llmKeys[providerId];
 87→  if (!keyConfig?.key) throw new Error('未配置大模型API Key');
 88→
 89→  const model = keyConfig.model || provider.defaultModel;
 90→  const prompt = PROMPT_TEMPLATE(audioText, docText);
 91→
 92→  let content: string;
 93→  if (providerId === 'claude') {
 94→    content = await callClaudeApi(prompt, keyConfig.key, model);
 95→  } else {
 96→    content = await callOpenAICompatible(prompt, keyConfig.key, provider.endpoint, model);
 97→  }
 98→
 99→  const jsonMatch = content.match(/\{[\s\S]*\}/);
100→  if (!jsonMatch) {
101→    return {diffs: [], summary: '对比完成，未发现差异或解析失败'};
102→  }
103→  try {
104→    return JSON.parse(jsonMatch[0]);
105→  } catch {
106→    return {diffs: [], summary: '对比结果解析失败: ' + content.substring(0, 200)};
107→  }
108→}
109→
110→// 测试大模型连接
111→export async function testLlmConnection(providerId: LlmProviderId, apiKey: string, model?: string): Promise<{ok: boolean; msg: string}> {
112→  const provider = LLM_PROVIDERS[providerId];
113→  const m = model || provider.defaultModel;
114→  const prompt = '请回复"连接成功"四个字。';
115→
116→  try {
117→    let content: string;
118→    if (providerId === 'claude') {
119→      content = await callClaudeApi(prompt, apiKey, m);
120→    } else {
121→      content = await callOpenAICompatible(prompt, apiKey, provider.endpoint, m);
122→    }
123→    return {ok: !!content, msg: content ? `连接成功: ${content.substring(0, 50)}` : '无响应'};
124→  } catch (e: any) {
125→    return {ok: false, msg: `连接失败: ${e.message}`};
126→  }
127→}
