  1→import RNFS from 'react-native-fs';
  2→import {AppConfig, ASR_PROVIDERS, AsrProviderId} from '../utils/config';
  3→import crypto from 'crypto-js';
  4→
  5→// 通用转写入口
  6→export async function transcribeAudio(filePath: string, config: AppConfig): Promise<string> {
  7→  const providerId = config.asrProvider;
  8→  const keyConfig = config.asrKeys[providerId];
  9→  if (!keyConfig?.key) throw new Error('未配置语音识别API Key');
 10→
 11→  switch (providerId) {
 12→    case 'aliyun': return transcribeAliyun(filePath, keyConfig.key, keyConfig.secret || '', keyConfig.appKey || '');
 13→    case 'xfyun': return transcribeXfyun(filePath, keyConfig.key, keyConfig.secret || '', keyConfig.appKey || '');
 14→    case 'tencent': return transcribeTencent(filePath, keyConfig.key, keyConfig.secret || '');
 15→    case 'baidu': return transcribeBaidu(filePath, keyConfig.key, keyConfig.secret || '');
 16→    case 'openai_whisper': return transcribeOpenAIWhisper(filePath, keyConfig.key);
 17→    case 'google': return transcribeGoogle(filePath, keyConfig.key);
 18→    case 'azure': return transcribeAzure(filePath, keyConfig.key, keyConfig.region || 'eastasia');
 19→    case 'aws': return transcribeAWS(filePath, keyConfig.key, keyConfig.secret || '', keyConfig.region || 'us-east-1');
 20→    default: throw new Error('不支持的转写服务: ' + providerId);
 21→  }
 22→}
 23→
 24→// 阿里云
 25→async function transcribeAliyun(filePath: string, akId: string, akSecret: string, appKey: string): Promise<string> {
 26→  // 获取Token
 27→  const nonce = Math.random().toString(36).substring(2);
 28→  const timestamp = new Date().toISOString().replace(/\.\d+Z$/, 'Z');
 29→  const params: Record<string, string> = {
 30→    AccessKeyId: akId, Action: 'CreateToken', Format: 'JSON',
 31→    RegionId: 'cn-shanghai', SignatureMethod: 'HMAC-SHA1',
 32→    SignatureNonce: nonce, SignatureVersion: '1.0',
 33→    Timestamp: timestamp, Version: '2019-02-28',
 34→  };
 35→  const sortedKeys = Object.keys(params).sort();
 36→  const canonicalized = sortedKeys.map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`).join('&');
 37→  const stringToSign = `GET&${encodeURIComponent('/')}&${encodeURIComponent(canonicalized)}`;
 38→  params.Signature = crypto.HmacSHA1(stringToSign, akSecret + '&').toString(crypto.enc.Base64);
 39→  const query = Object.keys(params).map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`).join('&');
 40→  const tokenResp = await fetch(`https://nls-meta.cn-shanghai.aliyuncs.com/?${query}`);
 41→  const tokenData = await tokenResp.json();
 42→  const token = tokenData?.Token?.Id;
 43→  if (!token) throw new Error('获取阿里云Token失败');
 44→
 45→  const audioBase64 = await RNFS.readFile(filePath, 'base64');
 46→  const audioBytes = Uint8Array.from(atob(audioBase64), c => c.charCodeAt(0));
 47→  const url = `https://nls-gateway-cn-shanghai.aliyuncs.com/stream/v1/asr?appkey=${appKey}&format=pcm&sample_rate=16000&enable_punctuation_prediction=true&enable_inverse_text_normalization=true`;
 48→  const resp = await fetch(url, {
 49→    method: 'POST',
 50→    headers: {'X-NLS-Token': token, 'Content-Type': 'application/octet-stream'},
 51→    body: audioBytes,
 52→  });
 53→  const result = await resp.json();
 54→  if (result.status === 20000000 && result.result) return result.result;
 55→  throw new Error('阿里云识别失败: ' + JSON.stringify(result));
 56→}
